const body = $json.body || {};

const channel = body.channel || 'whatsapp';
const channelUserId = body.from || null;

return [
  {
    json: {
      channel,
      channelUserId,
      sessionId: `${channel}:${channelUserId}`,
      messageText: body.text || '',
      attachments: Array.isArray(body.attachments) ? body.attachments : [],
      receivedAt: new Date().toISOString()
    }
  }
];

const normalized = $('Normalize Input').first().json;
const dbRow = $json;

let context;
let isNew = false;

if (!dbRow || !dbRow.session_id) {
  isNew = true;
  context = {
    session_id: normalized.sessionId,
    channel: normalized.channel,
    channel_user_id: normalized.channelUserId,
    stage: 'discovery',
    lead: {},
    energy: {},
    installation: {},
    location: {},
    backend: {},
    conversation: {
      missing_fields: []
    }
  };
} else {
  context = dbRow.context_json || {};
}

return [{
  json: {
    ...normalized,
    sessionId: normalized.sessionId,
    context,
    isNewSession: isNew
  }
}];

// The LLM Chain returns the response in $json.text
const rawText = $json.text || $json.output || '';

let parsed;
try {
  // Strip markdown code fences if the LLM wrapped the JSON
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch (e) {
  // Fallback: LLM returned something that isn't valid JSON
  parsed = {
    entities_to_save: {},
    missing_fields: [],
    is_ready_for_quote: false,
    next_goal: '',
    draft_reply: 'Desculpe, não entendi muito bem. Pode repetir sua mensagem?'
  };
}

// Get the original session data from Resolve Session
const base = $('Resolve Session').first().json;
const context = JSON.parse(JSON.stringify(base.context || {}));

// Ensure all context sections exist
context.lead         = context.lead         || {};
context.energy       = context.energy       || {};
context.installation = context.installation || {};
context.location     = context.location     || {};
context.conversation = context.conversation || {};

// Merge extracted entities into context
const entities = parsed.entities_to_save || {};
if (entities.lead)         Object.assign(context.lead,         entities.lead);
if (entities.energy)       Object.assign(context.energy,       entities.energy);
if (entities.installation) Object.assign(context.installation, entities.installation);

// Update conversation metadata
context.conversation.missing_fields    = parsed.missing_fields || [];
context.conversation.last_user_message = base.messageText;
context.conversation.last_bot_message  = parsed.draft_reply;

return [{
  json: {
    ...base,
    context,
    outboundText: parsed.draft_reply,
    isReadyForQuote: parsed.is_ready_for_quote === true,
    llmOutput: parsed
  }
}];

const ctx = $json.context || {};
const lead = ctx.lead || {};
const energy = ctx.energy || {};
const installation = ctx.installation || {};

return [{
  json: {
    ...$json,
    apiPayload: {
      lead: {
        full_name:    lead.full_name    || null,
        phone:        $json.channelUserId || null,
        city:         lead.city         || null,
        state:        lead.state        || null,
        address_text: lead.address_text || null,
        source: 'whatsapp'
      },
      budget_request: {
        monthly_consumption_kwh: energy.monthly_consumption_kwh || null,
        bill_amount_brl:         energy.bill_amount_brl         || null,
        utility_company:         energy.utility_company         || null,
        connection_type:         energy.connection_type         || null,
        installation_type:       installation.installation_type || null,
        roof_type:               installation.roof_type         || null
      },
      kits_limit: 3
    }
  }
}];

// Response from the Iara Solar API
const apiResponse = $json;
const quote = apiResponse.quote_version || {};
const kits  = apiResponse.suggested_kits || [];

// Original session data (for sessionId, context, etc.)
const base = $('Parse LLM Response').first().json;
const context = JSON.parse(JSON.stringify(base.context || {}));

// Store quote result in context for future messages
context.backend = context.backend || {};
context.backend.quote_generated = true;
context.backend.quote_id        = quote.id || null;
context.backend.quote_kwp       = quote.estimated_system_kwp || null;
context.backend.quote_price     = quote.estimated_price_brl  || null;

// Build a friendly reply in Portuguese
const kwp    = Number(quote.estimated_system_kwp || 0).toFixed(2);
const price  = Number(quote.estimated_price_brl  || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const saving = Number(quote.estimated_savings_brl || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

let reply = `Perfeito, ${context.lead.full_name || 'cliente'}! Aqui está sua estimativa inicial:\n\n`;
reply += `⚡ Sistema estimado: *${kwp} kWp*\n`;
reply += `💰 Investimento estimado: *${price}*\n`;
reply += `💡 Economia mensal estimada: *${saving}*\n`;

if (kits.length > 0) {
  reply += `\n*Kits disponíveis mais próximos do seu perfil:*\n`;
  kits.forEach((kit, i) => {
    const kitPrice = kit.price_cash_brl
      ? Number(kit.price_cash_brl).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })
      : 'consultar';
    reply += `${i + 1}. ${kit.supplier_kit_name} — ${kitPrice} à vista\n`;
  });
}

reply += `\nEssa é uma estimativa preliminar. Posso passar você para um de nossos consultores para detalhar a proposta. Tem interesse?`;

context.conversation.last_bot_message = reply;

return [{
  json: {
    ...base,
    context,
    outboundText: reply
  }
}];

return [
  {
    json: {
      session_id: $json.sessionId,
      direction: 'inbound',
      message_text: $json.messageText || '',
      payload_json: {
        channel: $json.channel,
        channelUserId: $json.channelUserId,
        messageText: $json.messageText,
        attachments: $json.attachments || [],
        receivedAt: $json.receivedAt
      }
    }
  }
];

if (!$json.sessionId) {
  throw new Error('sessionId não encontrado no fluxo');
}

return [
  {
    json: {
      session_id: $json.sessionId,
      direction: 'outbound',
      message_text: $json.outboundText || '',
      payload_json: {
        sessionId: $json.sessionId,
        reply: $json.outboundText || '',
        generatedAt: new Date().toISOString()
      }
    }
  }
];

return [
  {
    json: {
      ok: true,
      sessionId: $json.sessionId,
      reply: $json.outboundText || ''
    }
  }
];
